sys_variable_value.value:
(function(outputs, steps, params, stepResult, assertEqual) {
  // Create a second test email with only 2 key:value pairs in body_text
  var gr = new GlideRecord('sys_email');
  gr.initialize();
  gr.setValue('subject', '[ATF Test Data] Email Parsing Utilities Test Email - 2 Pairs');
  gr.setValue('body_text', 'Name: Jane Doe' + '\n' + 'Department: HR');
  gr.setValue('type', 'received');
  gr.setValue('state', 'processed');
  var sysId = gr.insert();
  if (!sysId) { stepResult.setFailed('FAIL: Could not create second test sys_email record'); return; }

  // Run action against it
  var emailRef = new GlideRecord('sys_email');
  emailRef.get(sysId);
  var inputs = { email: emailRef };
  var result = sn_fd.FlowAPI.getRunner().action('global.parse_email_body_text').inForeground().withInputs(inputs).run();
  var actionOutputs = result.getOutputs();
  var emailVar = actionOutputs['email_variables'] || actionOutputs['email_var'];
  if (!emailVar) { stepResult.setFailed('FAIL: email_variables output was null. Keys: ' + Object.keys(actionOutputs).join(',')); return; }
  var parsed = (typeof emailVar === 'string') ? JSON.parse(emailVar) : emailVar;
  if (Object.keys(parsed).length !== 2) { stepResult.setFailed('FAIL: Expected 2 pairs, got ' + Object.keys(parsed).length + ': ' + JSON.stringify(parsed)); return; }
  if (parsed['Name'] !== 'Jane Doe') { stepResult.setFailed('FAIL: Name expected "Jane Doe", got: ' + parsed['Name']); return; }
  if (parsed['Department'] !== 'HR') { stepResult.setFailed('FAIL: Department expected "HR", got: ' + parsed['Department']); return; }

  // Clean up the second email (Step 1 email is cleaned up by ATF Record Insert auto-delete)
  var cleanGr = new GlideRecord('sys_email');
  if (cleanGr.get(sysId)) { cleanGr.deleteRecord(); }

  stepResult.setSuccess();
  stepResult.setOutputMessage('PASS: 2-pair email body parsed correctly. Result: ' + JSON.stringify(parsed));
})(outputs, steps, params, stepResult, assertEqual);
